esqlQuery.esql:
FROM metrics-nginxreceiver.otel-*
// Filter to active connection state gauges
| WHERE state == "active"
// Aggregate active connections per host
| STATS avg_active = AVG(nginx.connections_current), max_active = MAX(nginx.connections_current), sample_count = COUNT(*) BY host.name
// Require minimum samples to avoid false positives during startup
| WHERE sample_count >= 3
// Alert when average active connections exceed capacity threshold
// Adjust threshold based on your NGINX worker_connections setting
| WHERE avg_active > 256
| SORT avg_active DESC
| LIMIT 10
